  1	import * as React from 'react';
  2	import SecondaryStatus from '@odf/shared/status/SecondaryStatus';
  3	import { HealthState } from '@openshift-console/dynamic-plugin-sdk';
  4	import classNames from 'classnames';
  5	import { Button, Popover, PopoverPosition } from '@patternfly/react-core';
  6	import { useCustomTranslation } from '../../useCustomTranslationHook';
  7	import { healthStateMapping, healthStateMessage } from './states';
  8	
  9	export type HealthItemProps = {
 10	  className?: string;
 11	  title: string;
 12	  details?: string;
 13	  state?: HealthState;
 14	  popupTitle?: string;
 15	  noIcon?: boolean;
 16	  icon?: React.ReactNode;
 17	  maxWidth?: string;
 18	  disableDetails?: boolean;
 19	  onClick?: () => void;
 20	};
 21	
 22	const HealthItemIcon: React.FC<HealthItemIconProps> = ({ state, dataTest }) => (
 23	  <div data-test={dataTest} className="co-dashboard-icon">
 24	    {
 25	      (healthStateMapping[state] || healthStateMapping[HealthState.UNKNOWN])
 26	        .icon
 27	    }
 28	  </div>
 29	);
 30	
 31	// eslint-disable-next-line react/display-name
 32	const HealthItem: React.FC<HealthItemProps> = React.memo(
 33	  ({
 34	    className,
 35	    state,
 36	    title,
 37	    details,
 38	    popupTitle,
 39	    noIcon = false,
 40	    icon,
 41	    children,
 42	    maxWidth,
 43	    disableDetails = false,
 44	    onClick,
 45	  }) => {
 46	    const { t } = useCustomTranslation();
 47	
 48	    const detailMessage = !disableDetails
 49	      ? details || healthStateMessage(state, t)
 50	      : '';
 51	
 52	    return (
 53	      <div
 54	        className={classNames('co-status-card__health-item', className)}
 55	        data-item-id={`${title}-health-item`}
 56	      >
 57	        {state === HealthState.LOADING ? (
 58	          <div className="skeleton-health">
 59	            <span className="pf-v6-u-screen-reader">
 60	              {t('Loading {{title}} status', { title })}
 61	            </span>
 62	          </div>
 63	        ) : (
 64	          !noIcon &&
 65	          (icon || (
 66	            <HealthItemIcon
 67	              state={state}
 68	              dataTest={`${title}-health-item-icon`}
 69	            />
 70	          ))
 71	        )}
 72	        <div>
 73	          <span className="co-status-card__health-item-text">
 74	            {(React.Children.toArray(children).length || onClick) &&
 75	            state !== HealthState.LOADING ? (
 76	              !onClick ? (
 77	                <Popover
 78	                  position={PopoverPosition.top}
 79	                  headerContent={popupTitle}
 80	                  bodyContent={children}
 81	                  enableFlip
 82	                  maxWidth={maxWidth || '21rem'}
 83	                >
 84	                  <Button
 85	                    variant="link"
 86	                    isInline
 87	                    className="co-status-card__popup"
 88	                    data-test="health-popover-link"
 89	                  >
 90	                    {title}
 91	                  </Button>
 92	                </Popover>
 93	              ) : (
 94	                <Button
 95	                  variant="link"
 96	                  isInline
 97	                  className="co-status-card__popup"
 98	                  data-test="health-popover-link"
 99	                  onClick={onClick}
100	                >
101	                  {title}
102	                </Button>
103	              )
104	            ) : (
105	              title
106	            )}
107	          </span>
108	          {state !== HealthState.LOADING && detailMessage && (
109	            <SecondaryStatus
110	              status={detailMessage}
111	              className="co-status-card__health-item-text"
112	              dataStatusID={`${title}-secondary-status`}
113	            />
114	          )}
115	        </div>
116	      </div>
117	    );
118	  }
119	);
120	
121	export default HealthItem;
122	
123	type HealthItemIconProps = {
124	  state?: HealthState;
125	  dataTest?: string;
126	};

