  1	import * as React from 'react';
  2	import { HealthState } from '@openshift-console/dynamic-plugin-sdk';
  3	import { render, screen } from '@testing-library/react';
  4	import HealthItem from './HealthItem';
  5	
  6	const classNames = jest.fn();
  7	jest.mock('classnames', () => (...props: string[]) => {
  8	  classNames(props);
  9	  return props[1] ? props[0] + ' ' + props[1] : props[0];
 10	});
 11	
 12	const mockSecondaryStatusComponent = jest.fn((_unused) => {
 13	  return <div data-test-id="mocked-secondary-status" />;
 14	});
 15	jest.mock(
 16	  '@odf/shared/status/SecondaryStatus',
 17	  () => (props) => mockSecondaryStatusComponent(props)
 18	);
 19	
 20	const mockPopOverComponent = jest.fn((_unused) => {
 21	  return <div data-test-id="mocked-pop-over" />;
 22	});
 23	
 24	const mockButtonComponent = jest.fn((_unused) => {
 25	  return <div data-test-id="mocked-button" />;
 26	});
 27	
 28	jest.mock('@patternfly/react-core', () => {
 29	  const originalModule = jest.requireActual('@patternfly/react-core');
 30	  return {
 31	    ...originalModule,
 32	    Popover: (props) => mockPopOverComponent(props),
 33	    Button: (props) => mockButtonComponent(props),
 34	  };
 35	});
 36	
 37	jest.mock('./states', () => ({
 38	  healthStateMapping: {
 39	    [HealthState.OK]: {
 40	      icon: 'unit-test-ok-icon',
 41	    },
 42	    [HealthState.UNKNOWN]: {
 43	      icon: 'unit-test-unknown-icon',
 44	    },
 45	  },
 46	  healthStateMessage: () => 'mocked-health-state-message',
 47	}));
 48	
 49	const title = 'unit-tests';
 50	
 51	describe('tests for document elements of health item component', () => {
 52	  it('should render only the title when in loading', () => {
 53	    render(<HealthItem title={title} state={HealthState.LOADING} />);
 54	    expect(screen.getByText(`${title}`)).toBeInTheDocument();
 55	  });
 56	  it('should not render popover when in loading', () => {
 57	    const { container } = render(
 58	      <HealthItem title={title} state={HealthState.LOADING} />
 59	    );
 60	    expect(
 61	      container.querySelector('[data-test-id="mocked-pop-over"]')
 62	    ).toBeNull();
 63	    expect(mockPopOverComponent).not.toHaveBeenCalled();
 64	  });
 65	  it('should not render the secondary status when in loading', () => {
 66	    const { container } = render(
 67	      <HealthItem title={title} state={HealthState.LOADING} />
 68	    );
 69	    expect(
 70	      container.querySelector('[data-test-id="mocked-secondary-status"]')
 71	    ).toBeNull();
 72	  });
 73	  it('should not render the icon status if no icon set to true', () => {
 74	    const { container } = render(
 75	      <HealthItem title={title} noIcon={true} state={HealthState.OK} />
 76	    );
 77	    expect(
 78	      container.querySelector(`[data-test="${title}-health-item-icon"]`)
 79	    ).toBeNull();
 80	  });
 81	  it('should render the status icon if no icon is left default as false and no icon is passed', () => {
 82	    const { container } = render(
 83	      <HealthItem title={title} state={HealthState.OK} />
 84	    );
 85	    expect(
 86	      container.querySelector(`[data-test="${title}-health-item-icon"]`)
 87	    ).toHaveTextContent('unit-test-ok-icon');
 88	  });
 89	  it('should render the default unknown icon if no icon is left default as false and no icon and state is passed', () => {
 90	    const { container } = render(<HealthItem title={title} />);
 91	    expect(
 92	      container.querySelector(`[data-test="${title}-health-item-icon"]`)
 93	    ).toHaveTextContent('unit-test-unknown-icon');
 94	  });
 95	  it('should render the passed icon if no icon is left default as false and a icon node is passed', () => {
 96	    const { container } = render(
 97	      <HealthItem
 98	        title={title}
 99	        icon={<div data-test="passed-health-item-icon" />}
100	      />
101	    );
102	    expect(
103	      container.querySelector(`[data-test="passed-health-item-icon"]`)
104	    ).toBeTruthy();
105	  });
106	  it('should not render the default icon if no icon is left default as false and a icon node is passed', () => {
107	    const { container } = render(
108	      <HealthItem
109	        title={title}
110	        icon={<div data-test="passed-health-item-icon" />}
111	      />
112	    );
113	    expect(
114	      container.querySelector(`[data-test="${title}-health-item-icon"]`)
115	    ).toBeNull();
116	  });
117	  it('should not render popover when no children is passed on', () => {
118	    const { container } = render(
119	      <HealthItem title={title} state={HealthState.OK} />
120	    );
121	    expect(
122	      container.querySelector('[data-test-id="mocked-pop-over"]')
123	    ).toBeNull();
124	    expect(mockPopOverComponent).not.toHaveBeenCalled();
125	  });
126	  it('should have popover when children is passed on and state is not in loading', () => {
127	    const { container } = render(
128	      <HealthItem title={title} state={HealthState.OK}>
129	        <div data-test-id="mocked-popover-content" />
130	      </HealthItem>
131	    );
132	    expect(
133	      container.querySelector('[data-test-id="mocked-pop-over"]')
134	    ).toBeTruthy();
135	    expect(mockPopOverComponent).toHaveBeenCalledWith(
136	      expect.objectContaining({
137	        enableFlip: true,
138	        maxWidth: '21rem',
139	        headerContent: undefined,
140	        position: 'top',
141	        bodyContent: <div data-test-id="mocked-popover-content" />,
142	      })
143	    );
144	  });
145	  it('should pass on the popup title to the popover', () => {
146	    const { container } = render(
147	      <HealthItem
148	        title={title}
149	        state={HealthState.OK}
150	        popupTitle="unit-test-popup-title"
151	      >
152	        <div data-test-id="mocked-popover-content" />
153	      </HealthItem>
154	    );
155	    expect(
156	      container.querySelector('[data-test-id="mocked-pop-over"]')
157	    ).toBeTruthy();
158	    expect(mockPopOverComponent).toHaveBeenCalledWith(
159	      expect.objectContaining({
160	        headerContent: 'unit-test-popup-title',
161	      })
162	    );
163	  });
164	  it('should pass on the width instead of default to the popover', () => {
165	    const { container } = render(
166	      <HealthItem title={title} state={HealthState.OK} maxWidth="100px">
167	        <div data-test-id="mocked-popover-content" />
168	      </HealthItem>
169	    );
170	    expect(
171	      container.querySelector('[data-test-id="mocked-pop-over"]')
172	    ).toBeTruthy();
173	    expect(mockPopOverComponent).toHaveBeenCalledWith(
174	      expect.objectContaining({
175	        maxWidth: '100px',
176	      })
177	    );
178	  });
179	  it('should not display secondary status when disable message is true', () => {
180	    const { container } = render(
181	      <HealthItem title={title} state={HealthState.OK} disableDetails={true} />
182	    );
183	    expect(
184	      container.querySelector('[data-test-id="mocked-secondary-status"]')
185	    ).toBeNull();
186	  });
187	  it('should display secondary status with default when disable message is false, message is not passed and status is not loading', () => {
188	    const { container } = render(
189	      <HealthItem title={title} state={HealthState.OK} disableDetails={false} />
190	    );
191	    expect(
192	      container.querySelector('[data-test-id="mocked-secondary-status"]')
193	    ).toBeTruthy();
194	    expect(mockSecondaryStatusComponent).toHaveBeenCalledWith(
195	      expect.objectContaining({
196	        status: 'mocked-health-state-message',
197	      })
198	    );
199	  });
200	  it('should display secondary status with passed message when disable message is false and status is not loading', () => {
201	    const { container } = render(
202	      <HealthItem
203	        title={title}
204	        state={HealthState.OK}
205	        disableDetails={false}
206	        details={'unit-test-passed-message'}
207	      />
208	    );
209	    expect(
210	      container.querySelector('[data-test-id="mocked-secondary-status"]')
211	    ).toBeTruthy();
212	    expect(mockSecondaryStatusComponent).toHaveBeenCalledWith(
213	      expect.objectContaining({
214	        status: 'unit-test-passed-message',
215	      })
216	    );
217	  });
218	});
219	
220	describe('tests for css classes for elements of health item component', () => {
221	  it('should have health item css class at root level', () => {
222	    const { container } = render(<HealthItem title={title} />);
223	    expect(
224	      container.querySelector(`[data-item-id="${title}-health-item"]`)
225	    ).toHaveClass('co-status-card__health-item');
226	    expect(classNames).toHaveBeenCalledWith(['co-status-card__health-item']);
227	  });
228	  it('should pass css class passed on as param to the component', () => {
229	    const { container } = render(
230	      <HealthItem
231	        title={title}
232	        state={HealthState.LOADING}
233	        className={'unit-test-css-class'}
234	      />
235	    );
236	    expect(
237	      container.querySelector(`[data-item-id="${title}-health-item"]`)
238	    ).toHaveClass('unit-test-css-class');
239	    expect(classNames).toHaveBeenCalledWith([
240	      'co-status-card__health-item',
241	      'unit-test-css-class',
242	    ]);
243	  });
244	  it('should check whether we have the loading class in case of loading', () => {
245	    const { container } = render(
246	      <HealthItem title={title} state={HealthState.LOADING} />
247	    );
248	    expect(container.querySelector('.skeleton-health')).toBeTruthy();
249	    expect(container.querySelector('.pf-v6-u-screen-reader')).toBeTruthy();
250	  });
251	  it('should check the css for the icon displayed', () => {
252	    const { container } = render(<HealthItem title={title} />);
253	    expect(
254	      container.querySelector(`[data-test="${title}-health-item-icon"]`)
255	    ).toHaveClass('co-dashboard-icon');
256	  });
257	  it('should check the css for the secondary status', () => {
258	    render(
259	      <HealthItem title={title} state={HealthState.OK} disableDetails={false} />
260	    );
261	    expect(mockSecondaryStatusComponent).toHaveBeenCalledWith(
262	      expect.objectContaining({
263	        className: 'co-status-card__health-item-text',
264	      })
265	    );
266	  });
267	});

